export class AiEstimate extends HTMLElement {
    /** The picked file, held until upload time. No client-side resize — server does it (story 124). */
    private _imageFile: File | null = null;
    /** Local object URL for the input preview; revoked on clear. */
    private _previewUrl: string | null = null;
    /** Server-side directory key returned by the upload endpoint (e.g. 'images/ai/<uuidv7>'). */
    private _imagePath: string | null = null;
    private _foodItemId: string | null = null;
    private _mealId: string | null = null;
    private _defaultDate: string | null = null;
    private _defaultMealType: MealType | null = null;
    /**
     * Story 206: ingredient-picker mode (story 122 return flow). The input is
     * ONE ingredient — the server skips decomposition and resolves it
     * directly, so the result is always kind 'food_item'.
     */
    private _singleMode = false;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        const shadow = this.shadowRoot!;

        // No BroadcastChannel subscription here: AI estimate requires the
        // image bytes to be on the server before the request can run, so the
        // queued path aborts in `doEstimate` rather than continuing with a
        // sentinel that the listener would have to swap out later.

        // Photo handling
        shadow.getElementById('btn-photo')!.addEventListener('click', () => {
            shadow.getElementById('photo-input')!.click();
        });

        shadow.getElementById('photo-input')!.addEventListener('change', (e) => {
            const input = e.target as HTMLInputElement;
            if (input.files?.[0]) {
                this.loadImage(input.files[0]);
            }
        });

        shadow.getElementById('btn-remove-photo')!.addEventListener('click', () => {
            this.clearImage();
        });

        // Estimate button
        shadow.getElementById('btn-estimate')!.addEventListener('click', () => {
            this.doEstimate();
        });

        // Retry button
        shadow.getElementById('btn-retry')!.addEventListener('click', () => {
            this.showInputView();
        });

        // Save button
        shadow.getElementById('btn-save')!.addEventListener('click', () => {
            this.doSave();
        });

        // Meal result actions (story 206)
        shadow.getElementById('btn-meal-retry')!.addEventListener('click', () => {
            this.showInputView();
        });
        shadow.getElementById('btn-meal-edit')!.addEventListener('click', () => {
            if (this._mealId) this.dispatchEvent(createAiMealEditEvent({ meal_id: this._mealId }));
        });
        shadow.getElementById('btn-meal-log')!.addEventListener('click', () => {
            this.doLogMeal();
        });

        // Archive-this-estimate. The AI result writes a food_items row + a
        // 1:1 ai_estimations subtype row (CASCADE). Archiving the food_items
        // row removes it from the picker (search/recent/frequent filter on
        // archived_at IS NULL). The ai_estimations row is left alone — it's
        // history of how the food_item was created. Story 120.
        shadow.getElementById('btn-archive')!.addEventListener('click', () => {
            this.doArchive();
        });

        // Error back button
        shadow.getElementById('btn-error-back')!.addEventListener('click', () => {
            this.showInputView();
        });

        // Apply route-provided defaults if present; otherwise fall back to today/default meal.
        this.applyDefaults();
    }

    set defaultDate(dateStr: string | null) {
        this._defaultDate = dateStr && dateStr.trim() ? dateStr : null;
        this.applyDefaults();
    }

    set defaultMealType(mealType: string | null) {
        if (!mealType || !MEAL_TYPES.includes(mealType as MealType)) {
            this._defaultMealType = null;
            this.applyDefaults();
            return;
        }

        this._defaultMealType = mealType as MealType;
        this.applyDefaults();
    }

    set singleMode(value: boolean) {
        this._singleMode = value;
    }

    private loadImage(file: File): void {
        const shadow = this.shadowRoot!;
        this._imageFile = file;
        // The server-side path doesn't exist yet — upload happens at submit time.
        this._imagePath = null;

        // Preview from the picked file directly (no resize). The server-side
        // pipeline handles EXIF rotation and resizing on upload.
        if (this._previewUrl) URL.revokeObjectURL(this._previewUrl);
        this._previewUrl = URL.createObjectURL(file);

        const preview = shadow.getElementById('photo-preview') as HTMLImageElement;
        preview.src = this._previewUrl;
        preview.alt = 'Selected meal photo';
        preview.hidden = false;
        shadow.getElementById('btn-remove-photo')!.hidden = false;
    }

    private clearImage(): void {
        const shadow = this.shadowRoot!;
        this._imageFile = null;
        this._imagePath = null;
        if (this._previewUrl) {
            URL.revokeObjectURL(this._previewUrl);
            this._previewUrl = null;
        }
        const preview = shadow.getElementById('photo-preview') as HTMLImageElement;
        preview.hidden = true;
        preview.src = '';
        shadow.getElementById('btn-remove-photo')!.hidden = true;
        (shadow.getElementById('photo-input') as HTMLInputElement).value = '';
    }

    private showInputView(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('input-view')!.hidden = false;
        shadow.getElementById('loading-view')!.hidden = true;
        shadow.getElementById('result-view')!.hidden = true;
        shadow.getElementById('meal-result-view')!.hidden = true;
        shadow.getElementById('error-view')!.hidden = true;
    }

    private async doEstimate(): Promise<void> {
        const shadow = this.shadowRoot!;
        const description = (shadow.getElementById('description') as HTMLTextAreaElement).value.trim();

        if (!description && !this._imageFile) {
            (shadow.getElementById('description') as HTMLTextAreaElement).focus();
            return;
        }

        // Show loading
        shadow.getElementById('input-view')!.hidden = true;
        shadow.getElementById('loading-view')!.hidden = false;

        const loadingText = shadow.getElementById('loading-text')!;
        loadingText.textContent = 'Analyzing your meal…';

        // Update loading message after a few seconds (cold start)
        const slowTimer = setTimeout(() => {
            loadingText.textContent = 'Starting AI engine… this may take a moment';
        }, 5000);

        try {
            // Story 211/221: any meal-logging estimation with a day/meal slot —
            // photo OR text-only — goes async. Hand the submit (raw photo bytes
            // included) to the screen, which persists it to the durable submit
            // queue and navigates to the review screen. The image uploads in the
            // drain, so the submit survives being offline and the app never
            // blocks on a slow upload. The ingredient-picker (single mode) stays
            // synchronous — it returns one ingredient to a caller waiting inline.
            if (!this._singleMode && this._defaultDate && this._defaultMealType) {
                clearTimeout(slowTimer);
                await this.requestAsyncEstimate({
                    description: description || undefined,
                    image_file: this._imageFile ?? undefined,
                    image_path: this._imagePath ?? undefined,
                    date: this._defaultDate,
                    meal_type: this._defaultMealType,
                });
                // The screen navigates to /health/estimates/:id; on failure
                // requestAsyncEstimate throws and the catch shows it.
                return;
            }

            // Synchronous path (ingredient picker / no day-meal slot): the
            // caller waits inline, so upload the photo now and estimate directly.
            if (this._imageFile && !this._imagePath) {
                const result = await FilesService.uploadImageOrQueue('ai', this._imageFile, this._imageFile.name || 'meal.jpg');
                if (result.status === 'uploaded') {
                    this._imagePath = result.image_path;
                } else {
                    // No day/meal slot to defer into — the caller needs the
                    // result now. Abort honestly; retry once the photo uploads.
                    clearTimeout(slowTimer);
                    this.showError(
                        'Your photo is queued for upload (offline or server unreachable). Try the estimate again once it has uploaded.',
                    );
                    return;
                }
            }

            const result = await this.requestEstimate(description || 'meal in photo', this._imagePath ?? undefined);
            clearTimeout(slowTimer);
            if (result.kind === 'meal') {
                this._mealId = result.meal.id;
                this._foodItemId = null;
                this._imagePath = result.meal.image_path ?? this._imagePath;
                this.showMealResult(result.meal, result.ingredients, result.confidence_score, result.notes);
            } else {
                this._foodItemId = result.food_item.id;
                this._mealId = null;
                // The food item's image_path is the source of truth for what to
                // display going forward (DLR #125).
                this._imagePath = result.food_item.image_path ?? this._imagePath;
                this.showFoodItemResult(result.food_item, result.resolution);
            }
        } catch (err) {
            clearTimeout(slowTimer);
            const message = err instanceof Error ? err.message : 'Unknown error';
            this.showError(message);
        }
    }

    private showFoodItemResult(foodItem: FoodItem, resolution: ResolvedMealIngredient): void {
        const shadow = this.shadowRoot!;

        shadow.getElementById('loading-view')!.hidden = true;
        shadow.getElementById('result-view')!.hidden = false;

        const resultImage = shadow.getElementById('result-image') as HTMLImageElement;
        if (this._imagePath) {
            resultImage.src = FilesService.variantUrl(this._imagePath, 'display.jpg');
            resultImage.hidden = false;
        } else {
            resultImage.hidden = true;
            resultImage.removeAttribute('src');
        }

        (shadow.getElementById('food-name') as HTMLInputElement).value = foodItem.display_name;
        (shadow.getElementById('serving-form') as FoodServingForm).data =
            foodItemToFormData(foodItem, resolution.amount || foodItem.default_serving_amount || foodItem.base_amount);

        // Provenance instead of the old confidence bucket: how this food was
        // bound (your library / OFF / AI-generated) is the actionable signal.
        const badge = shadow.getElementById('confidence-badge')!;
        badge.replaceChildren(createProvenanceBadge(resolution));
        badge.className = 'confidence-badge';

        const notes = shadow.getElementById('notes-text')!;
        notes.textContent = '';
        notes.hidden = true;
    }

    private showMealResult(meal: MealWithIngredients, resolutions: ResolvedMealIngredient[], confidence?: number, notesText?: string): void {
        const shadow = this.shadowRoot!;

        shadow.getElementById('loading-view')!.hidden = true;
        shadow.getElementById('meal-result-view')!.hidden = false;

        // The read-only display lives in the <ai-meal-result> child (story 237);
        // this view still owns the meal/date slot + action buttons below it.
        (shadow.getElementById('meal-result') as AiMealResult).data = {
            meal,
            resolutions,
            confidence,
            notes: notesText,
            imagePath: this._imagePath,
        };
    }

    private doLogMeal(): void {
        const shadow = this.shadowRoot!;
        if (!this._mealId) return;
        const meal_type = (shadow.getElementById('meal-meal-type') as HTMLSelectElement).value as MealType;
        const date = (shadow.getElementById('meal-log-date') as HTMLInputElement).value;
        // Story 260: editable eaten-at, defaulted to "now"; cleared → unstamped.
        const time = (shadow.getElementById('meal-log-time') as HTMLInputElement).value;
        this.dispatchEvent(createLogMealEvent({ meal_id: this._mealId, date, meal_type, consumed_time: time ? time : null }));
    }

    private showError(message: string): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('loading-view')!.hidden = true;
        shadow.getElementById('error-view')!.hidden = false;
        shadow.getElementById('error-text')!.textContent = message;
    }

    private async doArchive(): Promise<void> {
        if (!this._foodItemId) return;
        const btn = this.shadowRoot!.getElementById('btn-archive') as HTMLButtonElement;
        btn.disabled = true;
        try {
            await HealthService.updateFoodItem(this._foodItemId, {
                archived_at: Temporal.Now.instant().toString(),
            });
            this.reset();
        } finally {
            btn.disabled = false;
        }
    }

    private doSave(): void {
        const shadow = this.shadowRoot!;
        const food_name = (shadow.getElementById('food-name') as HTMLInputElement).value.trim();
        const meal_type = (shadow.getElementById('meal-type') as HTMLSelectElement).value as MealType;
        const date = (shadow.getElementById('log-date') as HTMLInputElement).value;

        if (!food_name || !this._foodItemId) return;

        const form = shadow.getElementById('serving-form') as FoodServingForm;
        const { servingAmount, serving } = form.getCurrentValues();

        this.dispatchEvent(createLogAiEstimateEvent({
            food_item_id: this._foodItemId,
            amount: servingAmount,
            meal_type,
            date,
            calories: serving.calories,
            protein_g: serving.protein_g,
            carbs_g: serving.carbs_g,
            fat_g: serving.fat_g,
            fiber_g: serving.fiber_g,
            sugar_g: serving.sugar_g,
        }));
    }

    private async requestEstimate(description: string, image_path?: string): Promise<MealEstimateResult> {
        const event = createEstimateNutritionEvent({
            description,
            image_path,
            single: this._singleMode || undefined,
            respondWith: null,
        });

        this.dispatchEvent(event);

        if (!event.detail.respondWith) {
            throw new Error('Estimate handler not set');
        }

        return await event.detail.respondWith;
    }

    private async requestAsyncEstimate(detail: { description?: string; image_file?: File; image_path?: string; date: string; meal_type: MealType }): Promise<void> {
        const event = createSubmitEstimateAsyncEvent({ ...detail, respondWith: null });
        this.dispatchEvent(event);
        if (!event.detail.respondWith) {
            throw new Error('Async estimate handler not set');
        }
        await event.detail.respondWith;
    }

    /** Reset to initial input state */
    reset(): void {
        this.showInputView();
        const shadow = this.shadowRoot!;
        (shadow.getElementById('description') as HTMLTextAreaElement).value = '';
        this.clearImage();
        // Also ensure preview is hidden and cleared
        const preview = shadow.getElementById('photo-preview') as HTMLImageElement;
        preview.hidden = true;
        preview.src = '';
        preview.alt = 'Preview';
        this.applyDefaults();
    }

    private applyDefaults(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;

        for (const id of ['log-date', 'meal-log-date']) {
            const dateInput = shadow.getElementById(id) as HTMLInputElement | null;
            if (dateInput) {
                dateInput.value = this._defaultDate ?? appTodayString();
            }
        }

        for (const id of ['meal-type', 'meal-meal-type']) {
            const mealInput = shadow.getElementById(id) as HTMLSelectElement | null;
            if (mealInput) {
                mealInput.value = this._defaultMealType ?? getDefaultMealType();
            }
        }

        // Story 260: eaten-at defaults to "now" in the app zone, editable.
        const timeInput = shadow.getElementById('meal-log-time') as HTMLInputElement | null;
        if (timeInput) {
            timeInput.value = nowHHMM(getAppTimeZone());
        }
    }
}

customElements.define('ai-estimate', AiEstimate);
