import type { ResolutionProvenance, ResolvedMealIngredient } from '@motivation/shared';

/**
 * How an ingredient/food was bound (your library / OFF / AI-generated) — the
 * actionable signal that replaced the old confidence bucket. Shared by the
 * single-food result (in `ai-estimate.component`) and the multi-ingredient
 * result (`ai-meal-result`), which is why it lives in its own module rather
 * than on either component.
 */
const PROVENANCE_LABELS: Record<ResolutionProvenance, { label: string; cls: string }> = {
    matched_library: { label: '📚 library', cls: 'provenance-library' },
    matched_off: { label: '🛒 OFF', cls: 'provenance-off' },
    generated: { label: '🤖 AI', cls: 'provenance-generated' },
};

export function createProvenanceBadge(resolution: ResolvedMealIngredient): HTMLSpanElement {
    const { label, cls } = PROVENANCE_LABELS[resolution.provenance];
    const badge = document.createElement('span');
    badge.className = `provenance-badge ${cls}`;
    badge.textContent = label;
    badge.title = resolution.similarity !== null
        ? `${resolution.tier} match (${Math.round(resolution.similarity * 100)}%)`
        : resolution.tier;
    return badge;
}
