import { HealthService } from '../../services/health.service.js';
import { popOutOfFlow, navigate } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import './ai-estimate/ai-estimate.component.js';
import type { AiEstimate } from './ai-estimate/ai-estimate.component.js';
import {
    HEALTH_EVENTS,
    type AiMealEditEvent,
    type EstimateNutritionEvent,
    type LogAiEstimateEvent,
    type LogMealEvent,
    type SubmitEstimateAsyncEvent,
} from './health-events.js';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';

export class HealthAiEstimateScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private dateValue: string | null = null;
    private mealValue: string | null = null;
    private returnPath: string | null = null;
    private readonly log = createComponentLogger('health-ai-estimate-screen');

    setLoading(): void {}
    setError(err: unknown): void {}
    clearStatus(): void {}

    private async returnToOrigin(): Promise<void> {
        const fallback = this.dateValue
            ? `/health/day/${encodeURIComponent(this.dateValue)}`
            : '/health';
        await popOutOfFlow(
            ['/health/food-entry', '/health/scanner', '/health/ai-estimate'],
            fallback,
        );
    }

    set date(value: string | null) {
        this.dateValue = value;
    }

    set meal(value: string | null) {
        this.mealValue = value;
    }

    set query(value: URLSearchParams | null) {
        this.returnPath = value?.get('return') ?? null;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Health', 'health', '/health');
        const aiEstimate = document.createElement('ai-estimate') as AiEstimate;
        aiEstimate.defaultDate = this.dateValue;
        aiEstimate.defaultMealType = this.mealValue;
        // Story 206: in the ingredient-picker flow (story 122 return URL) the
        // input is one ingredient — the server resolves it directly instead of
        // decomposing into a meal.
        aiEstimate.singleMode = !!this.returnPath;
        aiEstimate.addEventListener(HEALTH_EVENTS.ESTIMATE_NUTRITION, (event: EstimateNutritionEvent) => {
            event.detail.respondWith = HealthService.estimateNutrition(
                event.detail.description,
                event.detail.image_path,
                event.detail.single ?? false,
            );
        });
        // Story 211/221: async submission (photo OR text-only) — persist the
        // submit to the durable queue *before* any network so it survives being
        // offline and the app closing, then hand off to the review screen. Kick
        // the drain (ships now if online) and register Background Sync (ships on
        // reconnect if the app is closed); neither blocks the hand-off.
        aiEstimate.addEventListener(HEALTH_EVENTS.SUBMIT_ESTIMATE_ASYNC, (event: SubmitEstimateAsyncEvent) => {
            const { description, image_file, image_path, date, meal_type } = event.detail;
            event.detail.respondWith = (async () => {
                const { enqueueEstimateSubmit } = await import('../../services/offline/estimate-submit-store.js');
                const { shipPendingEstimateSubmits, requestEstimateSubmitSync } = await import('../../services/offline/estimate-submit-shipping.js');
                const clientSubmitId = await enqueueEstimateSubmit({
                    description,
                    date,
                    meal_type,
                    image: image_file ? { blob: image_file, filename: image_file.name || 'meal.jpg' } : null,
                    image_path,
                });
                navigate(`/health/estimates/${encodeURIComponent(clientSubmitId)}?pending=1`);
                void shipPendingEstimateSubmits().catch((err) =>
                    this.log.warn('estimate submit drain failed', { error: err instanceof Error ? err.message : String(err) }));
                void requestEstimateSubmitSync().catch(() => { /* falls back to the online / startup drain */ });
            })();
        });
        // Story 206: log the AI-assembled meal (atomic logMeal expansion) and
        // return to where the flow started.
        aiEstimate.addEventListener(HEALTH_EVENTS.LOG_MEAL, async (event: LogMealEvent) => {
            const { meal_id, ...payload } = event.detail;
            return safeExec(this, this.log, async () => {
                await HealthService.logMeal(meal_id, payload);
                await this.returnToOrigin();
            });
        });
        // Story 206: ingredient swapping reuses the meal editor — the meals
        // screen focuses the card and offers the full picker (scan/search/AI).
        aiEstimate.addEventListener(HEALTH_EVENTS.AI_MEAL_EDIT, (event: AiMealEditEvent) => {
            navigate(`/health/meals?focus=${encodeURIComponent(event.detail.meal_id)}`);
        });
        aiEstimate.addEventListener(HEALTH_EVENTS.LOG_AI_ESTIMATE, async (event: LogAiEstimateEvent) => {
            const entry = event.detail;
            return safeExec(this, this.log, async () => {
                if (this.returnPath) {
                    // Ingredient flow: the food_item was already persisted by
                    // POST /food-items/estimate. Skip the consumption entry and
                    // hand the food_item id back to the caller.
                    const target = `${this.returnPath}${this.returnPath.includes('?') ? '&' : '?'}addIngredientFoodId=${encodeURIComponent(entry.food_item_id)}`;
                    navigate(target, { history: 'replace' });
                    return;
                }
                await HealthService.createConsumptionEntry(entry);
                await this.returnToOrigin();
            });
        });

        page.content.appendChild(aiEstimate);
    }
}

customElements.define('health-ai-estimate-screen', HealthAiEstimateScreen);
