import stylesText from './ai-meal-result.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import type { MealWithIngredients, ResolvedMealIngredient } from '@motivation/shared';
import { FilesService } from '../../../../services/files.service.js';
import { createProvenanceBadge } from '../provenance-badge.js';

const styles = cssStyleSheet(stylesText);

/**
 * Story 237 — the read-only multi-ingredient meal result, extracted from
 * `ai-estimate.component` so the monolith no longer owns this rendering. Pure
 * presentation: it takes the decomposed meal + per-ingredient resolutions via
 * `data` and renders name, ingredient rows (amount · kcal · provenance), total,
 * and notes. The parent keeps the meal/date selects + action buttons and all
 * event wiring, so this child dispatches nothing.
 */
export interface AiMealResultData {
    meal: MealWithIngredients;
    resolutions: ResolvedMealIngredient[];
    confidence?: number;
    notes?: string;
    imagePath?: string | null;
}

const template = document.createElement('template');
template.innerHTML = `
    <img id="meal-result-image" class="result-image" alt="Your meal" hidden loading="eager" decoding="async">

    <div class="result-header">
        <div class="ai-badge">🤖 AI Meal</div>
        <span id="meal-confidence-badge" class="confidence-badge"></span>
    </div>

    <input type="text" id="meal-name" class="food-name-input" readonly>

    <ul id="ingredient-list" class="ingredient-list"></ul>
    <div id="meal-totals" class="meal-totals"></div>
    <div id="meal-notes" class="notes-text"></div>
`;

export class AiMealResult extends HTMLElement {
    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    set data(value: AiMealResultData) {
        this.render(value);
    }

    private render({ meal, resolutions, confidence, notes, imagePath }: AiMealResultData): void {
        const shadow = this.shadowRoot!;

        const resultImage = shadow.getElementById('meal-result-image') as HTMLImageElement;
        if (imagePath) {
            resultImage.src = FilesService.variantUrl(imagePath, 'display.jpg');
            resultImage.hidden = false;
        } else {
            resultImage.hidden = true;
            resultImage.removeAttribute('src');
        }

        (shadow.getElementById('meal-name') as HTMLInputElement).value = meal.name;

        const badge = shadow.getElementById('meal-confidence-badge')!;
        if (typeof confidence === 'number') {
            const tier: 'high' | 'medium' | 'low' = confidence >= 0.75 ? 'high' : confidence >= 0.5 ? 'medium' : 'low';
            badge.textContent = tier;
            badge.className = `confidence-badge confidence-${tier}`;
            badge.hidden = false;
        } else {
            badge.hidden = true;
        }

        const byFoodItem = new Map(resolutions.map((r) => [r.food_item_id, r]));
        const list = shadow.getElementById('ingredient-list')!;
        list.replaceChildren();
        let totalKcal = 0;
        for (const ingredient of meal.ingredients) {
            const item = ingredient.food_item;
            const resolution = byFoodItem.get(ingredient.food_item_id);

            const row = document.createElement('li');
            row.className = 'ingredient-row';

            const name = document.createElement('span');
            name.className = 'ingredient-name';
            name.textContent = item.display_name;

            const amount = document.createElement('span');
            amount.className = 'ingredient-amount';
            const kcal = item.calories_per_base != null && item.base_amount > 0
                ? (item.calories_per_base * ingredient.amount) / item.base_amount
                : null;
            if (kcal !== null) totalKcal += kcal;
            amount.textContent = `${ingredient.amount}${item.base_unit === 'piece' ? '×' : item.base_unit}${kcal !== null ? ` · ${Math.round(kcal)} kcal` : ''}`;

            row.append(name, amount);
            if (resolution) row.append(createProvenanceBadge(resolution));
            list.appendChild(row);
        }

        shadow.getElementById('meal-totals')!.textContent = `Total: ${Math.round(totalKcal)} kcal`;

        const notesEl = shadow.getElementById('meal-notes')!;
        notesEl.textContent = notes ?? '';
        notesEl.hidden = !notes;
    }
}

if (!customElements.get('ai-meal-result')) {
    customElements.define('ai-meal-result', AiMealResult);
}
